probe_css:
.probe-modal-box {
  min-width: 800px;
  max-width: 95vw;
  max-height: 90vh;
  display: flex;
  flex-direction: column;
  padding: 16px;
  overflow: hidden; /* SCHEME B: prevent inner content overflow pushing buttons out */
}
.probe-section {
  flex: 0 0 auto;
  min-height: 60px;
  display: flex;
  flex-direction: column;
  gap: 6px;
}
.probe-label {
  font-size: 11px;
  color: var(--text2);
  font-weight: 600;
}
.probe-sash {
  height: 6px;
  flex-shrink: 0;
  background: var(--bg3);
  border-top: 1px solid var(--border);
  border-bottom: 1px solid var(--border);
  cursor: row-resize;
  margin: 4px 0;
}
.probe-sash:hover { background: var(--blue); }
.probe-flex-mid {
  flex: 1 1 0;
  min-height: 0; /* critical: allow flex children to shrink */
  overflow: hidden;
  display: flex;
  flex-direction: column;
  border: 1px dashed rgba(78, 201, 176, 0.3); /* debug tint; safe to keep */
}
.probe-flex-mid > .probe-section { flex: 0 0 auto; min-height: 50px; }
.probe-flex-mid > .probe-section.probe-log-section { flex: 1 1 0; min-height: 0; overflow: hidden; }
.probe-flex-mid > .probe-log { flex: 1; overflow-y: auto; min-height: 0; }
.probe-actions { flex-shrink: 0; /* SCHEME B: never compress buttons */ }
.probe-models-list {
    flex: 1;
    min-height: 60px;
    max-height: 180px;
    overflow-y: auto;
    background: var(--bg);
    border: 1px solid var(--border);
    border-radius: 4px;
    padding: 6px;
    display: flex;
    flex-wrap: wrap;
    align-content: flex-start;
    gap: 4px 6px;
  }
.probe-model-item {
    display: inline-flex;
    align-items: center;
    gap: 5px;
    padding: 3px 9px;
    background: var(--bg2);
    border: 1px solid var(--border);
    border-radius: 12px;
    font-size: 11px;
    cursor: pointer;
    white-space: nowrap;
    transition: background 0.12s;
  }
.probe-model-item:hover { background: var(--bg3); }
.probe-model-item input { margin: 0; cursor: pointer; }
.probe-model-item .ctx-badge {
    font-size: 9px;
    color: var(--blue);
    padding-left: 3px;
  }
.probe-model-item.custom {
    border-color: var(--blue);
    background: rgba(79, 195, 247, 0.08);
  }
.probe-model-item.custom .model-name::before {
    content: "\271A";
    font-size: 9px;
    color: var(--blue);
    margin-right: 3px;
  }
.probe-model-item.add-pill {
    background: transparent;
    border: 1px dashed var(--border);
    padding: 3px 8px;
  }
.probe-model-item.add-pill input {
    border: none;
    background: transparent;
    color: var(--text);
    font-size: 11px;
    outline: none;
    width: 110px;
    padding: 0;
  }
.probe-model-item.add-pill input::placeholder { color: var(--text2); }
.probe-model-item.add-pill:focus-within { border-color: var(--blue); }
.probe-model-item {
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 4px 6px;
  cursor: pointer;
  border-radius: 3px;
}
.probe-model-item:hover { background: var(--bg3); }
.probe-model-item input { width: auto; margin: 0; flex-shrink: 0; }
.probe-model-name { flex: 1; font-size: 12px; }
.probe-model-ctx { font-size: 10px; color: var(--blue); min-width: 50px; text-align: right; }
.probe-caps-grid { display: flex; flex-wrap: wrap; gap: 8px 16px; }
.probe-caps-grid label { display: flex; align-items: center; gap: 4px; font-size: 11px; cursor: pointer; }
.probe-caps-grid input { width: auto; margin: 0; }
.probe-results-section { flex: 0 0 200px; min-height: 100px; }
.probe-table-wrap { flex: 1; overflow: auto; background: var(--bg); border: 1px solid var(--border); border-radius: 4px; }
.probe-log-section { flex: 1; min-height: 150px; }
.probe-log { flex: 1; min-height: 150px; overflow-y: auto; background: var(--bg); border: 1px solid var(--border); border-radius: 4px; padding: 8px; font-family: Consolas, monospace; font-size: 11px; color: #7ee787; white-space: pre-wrap; }
.probe-actions { display: flex; justify-content: space-between; align-items: center; padding-top: 12px; border-top: 1px solid var(--border); margin-top: 8px; }
.probe-actions-right { display: flex; gap: 8px; }
